(function initEconovariaAdminAuth() {
  "use strict";

  const SUPABASE_URL = "https://cgiukdjwicykrmtkhudh.supabase.co";
  const SUPABASE_PUBLISHABLE_KEY = "sb_publishable_zkbXiJ1_zlmQIBMky6oi5w_4A24T1iV";
  const CLASSROOM_API_URL = `${SUPABASE_URL}/functions/v1/classroom-api`;
  const SESSION_KEY = "econovaria.admin.auth.v1";
  const SELECTED_GAME_KEY = "econovaria.admin.selected-game.v1";
  const nativeFetch = window.fetch.bind(window);

  window.ECONOVARIA_ADMIN_MOTION_BACKGROUND = "data:video/mp4;base64,";

  const authState = {
    terminal: null,
    session: null,
    bootstrap: null,
    selectedGameId: "",
    initialized: false
  };

  window.ECONOVARIA_ADMIN_API_BASE_URL = "/api/admin";
  window.ECONOVARIA_ADMIN_REAUTH_URL = "./?reason=session-required";
  window.ECONOVARIA_ADMIN_ALLOWED_ORIGINS = [window.location.origin];

  function jsonResponse(status, payload) {
    return new Response(JSON.stringify(payload), {
      status,
      headers: { "Content-Type": "application/json", "Cache-Control": "no-store" }
    });
  }

  function readStoredSession() {
    try {
      const value = JSON.parse(window.sessionStorage.getItem(SESSION_KEY) || "null");
      return value && typeof value.accessToken === "string" ? value : null;
    } catch (_) {
      return null;
    }
  }

  function storeSession(session) {
    authState.session = session;
    if (session) window.sessionStorage.setItem(SESSION_KEY, JSON.stringify(session));
    else window.sessionStorage.removeItem(SESSION_KEY);
  }

  function parseJwt(token) {
    try {
      const payload = token.split(".")[1] || "";
      const normalized = payload.replace(/-/g, "+").replace(/_/g, "/");
      return JSON.parse(decodeURIComponent(Array.prototype.map.call(atob(normalized), (char) => `%${(`00${char.charCodeAt(0).toString(16)}`).slice(-2)}`).join("")));
    } catch (_) {
      return {};
    }
  }

  function getSelectedGame() {
    const games = Array.isArray(authState.bootstrap?.activeGameSessions) ? authState.bootstrap.activeGameSessions : [];
    return games.find((game) => String(game.id) === String(authState.selectedGameId)) || games[0] || null;
  }

  function mapAdminBootstrap() {
    const source = authState.bootstrap || {};
    const staff = source.staff || {};
    const games = Array.isArray(source.activeGameSessions) ? source.activeGameSessions : [];
    const selected = getSelectedGame();
    const claims = parseJwt(authState.session?.accessToken || "");
    const sessionId = claims.session_id || claims.sid || `${claims.sub || staff.supabaseAuthUserId || staff.id || "admin"}:${claims.iat || "session"}`;
    const csrfToken = authState.session?.csrfToken || "";

    return {
      data: {
        admin: {
          id: staff.id || claims.sub || "",
          accountId: staff.id || claims.sub || "",
          displayName: staff.displayName || staff.email || "Administrator",
          email: staff.email || claims.email || "",
          role: "game_admin",
          roles: ["game_admin"]
        },
        activeGame: selected ? {
          id: selected.id,
          name: selected.name,
          status: selected.status || "active",
          joinCode: selected.joinCode || selected.gameCode || ""
        } : {},
        games: games.map((game) => ({
          id: game.id,
          name: game.name,
          status: game.status || "active",
          joinCode: game.joinCode || game.gameCode || "",
          createdAt: game.createdAt || "",
          updatedAt: game.updatedAt || ""
        })),
        permissions: ["*"],
        roles: ["game_admin"],
        csrfToken,
        session: {
          id: sessionId,
          csrfToken,
          expiresAt: claims.exp ? new Date(Number(claims.exp) * 1000).toISOString() : ""
        }
      }
    };
  }

  async function readJson(response) {
    try { return await response.json(); } catch (_) { return null; }
  }

  async function classroomRequest(path, options = {}) {
    const token = authState.session?.accessToken || "";
    const headers = new Headers(options.headers || {});
    headers.set("apikey", SUPABASE_PUBLISHABLE_KEY);
    headers.set("Authorization", `Bearer ${token || SUPABASE_PUBLISHABLE_KEY}`);
    if (options.body && !headers.has("Content-Type")) headers.set("Content-Type", "application/json");
    return nativeFetch(`${CLASSROOM_API_URL}${path}`, { ...options, headers });
  }

  async function proxyExistingAdminRoute(pathname, request) {
    const gameStoreMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/store\/items(?:\/([^/]+))?$/);
    if (gameStoreMatch) {
      const gameId = decodeURIComponent(gameStoreMatch[1]);
      const itemId = gameStoreMatch[2] ? `/${encodeURIComponent(decodeURIComponent(gameStoreMatch[2]))}` : "";
      const response = await classroomRequest(`/games/${encodeURIComponent(gameId)}/store/items${itemId}`, {
        method: request.method,
        body: ["GET", "HEAD"].includes(request.method) ? undefined : await request.clone().text()
      });
      return response;
    }

    const settingsMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/settings$/);
    if (settingsMatch) {
      const gameId = decodeURIComponent(settingsMatch[1]);
      return classroomRequest(`/games/${encodeURIComponent(gameId)}/settings`, {
        method: request.method,
        body: ["GET", "HEAD"].includes(request.method) ? undefined : await request.clone().text()
      });
    }

    const playersMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/players$/);
    if (playersMatch && ["GET", "POST"].includes(request.method)) {
      const gameId = decodeURIComponent(playersMatch[1]);
      return classroomRequest(`/games/${encodeURIComponent(gameId)}/players`, {
        method: request.method,
        body: request.method === "GET" ? undefined : await request.clone().text()
      });
    }

    const accessCodeResetMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/players\/([^/]+)\/access-code\/reset$/);
    if (accessCodeResetMatch && request.method === "POST") {
      const gameId = decodeURIComponent(accessCodeResetMatch[1]);
      const playerId = decodeURIComponent(accessCodeResetMatch[2]);
      return classroomRequest(`/games/${encodeURIComponent(gameId)}/players/${encodeURIComponent(playerId)}/access-code/reset`, {
        method: "POST",
        body: await request.clone().text()
      });
    }

    const attendanceMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/attendance\/today$/);
    if (attendanceMatch && request.method === "GET") {
      const gameId = decodeURIComponent(attendanceMatch[1]);
      return classroomRequest(`/games/${encodeURIComponent(gameId)}/attendance`, { method: "GET" });
    }

    const attendanceScanMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/attendance\/scans$/);
    if (attendanceScanMatch && request.method === "POST") {
      const gameId = decodeURIComponent(attendanceScanMatch[1]);
      return classroomRequest(`/games/${encodeURIComponent(gameId)}/attendance/scan`, {
        method: "POST",
        body: await request.clone().text()
      });
    }

    const contractsMatch = pathname.match(/^\/api\/admin\/games\/([^/]+)\/contracts$/);
    if (contractsMatch) {
      const gameId = decodeURIComponent(contractsMatch[1]);
      return classroomRequest(`/staff/game-sessions/${encodeURIComponent(gameId)}/contracts`, {
        method: request.method,
        body: ["GET", "HEAD"].includes(request.method) ? undefined : await request.clone().text()
      });
    }

    return null;
  }

  window.fetch = async function econovariaAdminFetch(input, init) {
    const request = input instanceof Request ? input : new Request(input, init);
    const url = new URL(request.url, window.location.href);
    if (!url.pathname.startsWith("/api/admin")) return nativeFetch(input, init);

    if (!authState.session?.accessToken) {
      return jsonResponse(401, { code: "auth_required", message: "Administrator sign-in is required." });
    }

    if (url.pathname === "/api/admin/session/bootstrap" && request.method === "GET") {
      if (!authState.bootstrap) {
        const result = await loadStaffBootstrap();
        if (!result.ok) return jsonResponse(result.status || 401, { code: result.code || "staff_bootstrap_failed", message: result.message });
      }
      return jsonResponse(200, mapAdminBootstrap());
    }

    if (url.pathname === "/api/admin/auth/sign-out" && request.method === "POST") {
      try {
        await nativeFetch(`${SUPABASE_URL}/auth/v1/logout`, {
          method: "POST",
          headers: { apikey: SUPABASE_PUBLISHABLE_KEY, Authorization: `Bearer ${authState.session.accessToken}` }
        });
      } catch (_) {}
      clearAuthenticatedState();
      return jsonResponse(200, { data: { signedOut: true } });
    }

    if (url.pathname === "/api/admin/games" && request.method === "GET") {
      return jsonResponse(200, { data: { games: mapAdminBootstrap().data.games } });
    }

    const switchMatch = url.pathname.match(/^\/api\/admin\/games\/([^/]+)\/switch$/);
    if (switchMatch && request.method === "POST") {
      const nextGameId = decodeURIComponent(switchMatch[1]);
      const exists = (authState.bootstrap?.activeGameSessions || []).some((game) => String(game.id) === nextGameId);
      if (!exists) return jsonResponse(404, { code: "game_not_found", message: "That game is no longer available." });
      authState.selectedGameId = nextGameId;
      window.sessionStorage.setItem(SELECTED_GAME_KEY, nextGameId);
      syncLegacySessionBridge();
      return jsonResponse(200, { data: { activeGame: mapAdminBootstrap().data.activeGame } });
    }

    const proxied = await proxyExistingAdminRoute(url.pathname, request);
    if (proxied) return proxied;

    return jsonResponse(501, {
      code: "admin_route_not_implemented",
      message: "This admin operation is not connected to the Supabase classroom API yet.",
      path: url.pathname
    });
  };

  function makeCsrfToken() {
    const bytes = new Uint8Array(24);
    window.crypto.getRandomValues(bytes);
    return Array.from(bytes, (value) => value.toString(16).padStart(2, "0")).join("");
  }

  async function signIn(email, password) {
    const response = await nativeFetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        apikey: SUPABASE_PUBLISHABLE_KEY,
        Authorization: `Bearer ${SUPABASE_PUBLISHABLE_KEY}`
      },
      body: JSON.stringify({ email: String(email || "").trim(), password: String(password || "") })
    });
    const data = await readJson(response);
    if (!response.ok || !data?.access_token) {
      return { ok: false, status: response.status, message: data?.msg || data?.message || data?.error_description || "Admin email or Access Code is invalid." };
    }
    storeSession({
      accessToken: data.access_token,
      refreshToken: data.refresh_token || "",
      csrfToken: makeCsrfToken(),
      user: data.user || null
    });
    return { ok: true };
  }

  async function loadStaffBootstrap() {
    if (!authState.session?.accessToken) return { ok: false, status: 401, message: "Administrator sign-in is required." };
    const response = await classroomRequest("/staff/bootstrap", { method: "GET" });
    const data = await readJson(response);
    if (!response.ok || data?.ok !== true) {
      if (response.status === 401) clearAuthenticatedState();
      return { ok: false, status: response.status, code: data?.error?.code || data?.code, message: data?.error?.message || data?.message || "Admin session could not be loaded." };
    }
    authState.bootstrap = data;
    return { ok: true, data };
  }

  async function createAccount(payload) {
    const response = await nativeFetch(`${CLASSROOM_API_URL}/staff/signup`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        apikey: SUPABASE_PUBLISHABLE_KEY,
        Authorization: `Bearer ${SUPABASE_PUBLISHABLE_KEY}`
      },
      body: JSON.stringify(payload)
    });
    const data = await readJson(response);
    if (!response.ok || data?.ok !== true) {
      return { ok: false, status: response.status, message: data?.error?.message || data?.message || "Staff account signup failed." };
    }
    return { ok: true, data };
  }

  function syncLegacySessionBridge() {
    const source = authState.bootstrap || {};
    const staff = source.staff || {};
    const games = Array.isArray(source.activeGameSessions) ? source.activeGameSessions : [];
    window.currentSession = {
      role: "ADMIN",
      token: authState.session?.accessToken || "",
      authSource: "supabase-admin",
      permissions: ["*"],
      staffSession: {
        staffId: staff.id || "",
        staffEmail: staff.email || "",
        staffDisplayName: staff.displayName || staff.email || "Administrator",
        staffRole: "game_admin",
        activeGameSessions: games,
        selectedGameSessionId: authState.selectedGameId
      }
    };
    window.state = window.state || {};
    window.state.staffSession = window.currentSession.staffSession;
  }

  function clearAuthenticatedState() {
    authState.session = null;
    authState.bootstrap = null;
    authState.selectedGameId = "";
    window.sessionStorage.removeItem(SESSION_KEY);
    window.sessionStorage.removeItem(SELECTED_GAME_KEY);
    window.currentSession = null;
    if (window.state) window.state.staffSession = null;
  }

  function showMessage(element, message, isError) {
    if (!element) return;
    element.hidden = !message;
    element.textContent = message || "";
    element.classList.toggle("is-error", Boolean(isError));
  }

  function setBusy(form, busy, label) {
    const button = form?.querySelector("button[type='submit']");
    if (!button) return;
    if (!button.dataset.defaultLabel) button.dataset.defaultLabel = button.textContent;
    button.disabled = busy;
    button.textContent = busy ? label : button.dataset.defaultLabel;
  }

  function setAuthMode(mode) {
    document.querySelectorAll("[data-auth-mode]").forEach((button) => button.classList.toggle("is-active", button.dataset.authMode === mode));
    document.querySelectorAll("[data-pane]").forEach((pane) => pane.classList.toggle("is-active", pane.dataset.pane === mode));
  }

  function renderGameSelection() {
    const signInPane = document.querySelector('[data-pane="signin"]');
    const createPane = document.querySelector('[data-pane="create"]');
    const gamesPane = document.querySelector('[data-pane="games"]');
    const tabs = document.querySelector(".admin-auth-tabs");
    const list = document.getElementById("adminGameList");
    const games = authState.bootstrap?.activeGameSessions || [];
    signInPane?.classList.remove("is-active");
    createPane?.classList.remove("is-active");
    gamesPane?.classList.add("is-active");
    if (tabs) tabs.hidden = true;
    if (!list) return;
    list.replaceChildren();
    if (!games.length) {
      const empty = document.createElement("p");
      empty.className = "admin-auth-message is-error";
      empty.textContent = "No active game sessions are available for this administrator.";
      list.appendChild(empty);
      return;
    }
    games.forEach((game) => {
      const button = document.createElement("button");
      const title = document.createElement("strong");
      const detail = document.createElement("span");
      button.type = "button";
      button.className = "admin-auth-game";
      title.textContent = game.name || "Active game";
      detail.textContent = `${game.status || "active"} session`;
      button.append(title, detail);
      button.addEventListener("click", () => launchGame(game.id));
      list.appendChild(button);
    });
  }

  function launchGame(gameId) {
    authState.selectedGameId = String(gameId || "");
    window.sessionStorage.setItem(SELECTED_GAME_KEY, authState.selectedGameId);
    syncLegacySessionBridge();
    const root = document.getElementById("adminAuthRoot");
    const mount = authState.terminal?.mount;
    if (root) root.hidden = true;
    document.body.classList.remove("admin-auth-active");
    if (mount && authState.terminal?.feature) {
      mount.hidden = false;
      mount.innerHTML = authState.terminal.feature.renderShell();
    }
  }

  async function requestPasswordReset() {
    const form = document.getElementById("adminSignInForm");
    const message = document.getElementById("adminSignInMessage");
    const button = document.getElementById("adminForgotAccessCode");
    const email = form?.elements?.email?.value?.trim() || "";

    showMessage(message, "", false);

    if (!email) {
      return showMessage(message, "Enter your Admin Email first.", true);
    }

    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      return showMessage(message, "Enter a valid Admin Email.", true);
    }

    const redirectTo = new URL("../auth/reset-password.html", document.baseURI).href;
    if (button) button.disabled = true;

    try {
      const response = await nativeFetch(
        `${SUPABASE_URL}/auth/v1/recover?redirect_to=${encodeURIComponent(redirectTo)}`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            apikey: SUPABASE_PUBLISHABLE_KEY,
            Authorization: `Bearer ${SUPABASE_PUBLISHABLE_KEY}`
          },
          body: JSON.stringify({ email })
        }
      );

      const data = await readJson(response);

      if (!response.ok) {
        return showMessage(
          message,
          data?.msg || data?.message || data?.error_description || "The reset email could not be sent.",
          true
        );
      }

      showMessage(
        message,
        "If that administrator account exists, a password reset email has been sent.",
        false
      );
    } catch (_) {
      showMessage(message, "Could not connect to password recovery.", true);
    } finally {
      if (button) button.disabled = false;
    }
  }

  async function handleSignIn(event) {
    event.preventDefault();
    const form = event.currentTarget;
    const message = document.getElementById("adminSignInMessage");
    const email = form.elements.email.value.trim();
    const password = form.elements.password.value;
    showMessage(message, "", false);
    setBusy(form, true, "Verifying access...");
    try {
      const signInResult = await signIn(email, password);
      if (!signInResult.ok) return showMessage(message, signInResult.message, true);
      const bootstrap = await loadStaffBootstrap();
      if (!bootstrap.ok) return showMessage(message, bootstrap.message, true);
      renderGameSelection();
    } catch (_) {
      showMessage(message, "Could not connect to administrator sign-in.", true);
    } finally {
      setBusy(form, false);
    }
  }

  async function handleCreate(event) {
    event.preventDefault();
    const form = event.currentTarget;
    const message = document.getElementById("adminCreateMessage");
    const values = Object.fromEntries(new FormData(form).entries());
    showMessage(message, "", false);
    if (String(values.password || "").length < 8) return showMessage(message, "Access Code must be at least 8 characters.", true);
    if (values.password !== values.confirmPassword) return showMessage(message, "Access Code confirmation does not match.", true);
    setBusy(form, true, "Creating account...");
    try {
      const created = await createAccount({
        email: String(values.email || "").trim(),
        password: String(values.password || ""),
        displayName: String(values.displayName || "").trim(),
        purchaseCode: String(values.purchaseCode || "").trim(),
        gameName: String(values.gameName || "").trim(),
        difficultyPreset: String(values.difficultyPreset || "").trim()
      });
      if (!created.ok) return showMessage(message, created.message, true);
      const signedIn = await signIn(values.email, values.password);
      if (!signedIn.ok) return showMessage(message, `Account created, but sign-in failed: ${signedIn.message}`, true);
      const bootstrap = await loadStaffBootstrap();
      if (!bootstrap.ok) return showMessage(message, bootstrap.message, true);
      const createdId = created.data?.activation?.gameSessionId || "";
      if (createdId) return launchGame(createdId);
      renderGameSelection();
    } catch (_) {
      showMessage(message, "Could not create the staff account.", true);
    } finally {
      setBusy(form, false);
    }
  }

  function showSignIn() {
    clearAuthenticatedState();
    const root = document.getElementById("adminAuthRoot");
    const mount = authState.terminal?.mount;
    const tabs = document.querySelector(".admin-auth-tabs");
    if (root) root.hidden = false;
    if (mount) mount.hidden = true;
    if (tabs) tabs.hidden = false;
    document.body.classList.add("admin-auth-active");
    setAuthMode("signin");
  }

  async function restoreSession() {
    authState.session = readStoredSession();
    if (!authState.session) return showSignIn();
    const bootstrap = await loadStaffBootstrap();
    if (!bootstrap.ok) return showSignIn();
    const storedGame = window.sessionStorage.getItem(SELECTED_GAME_KEY) || "";
    const games = authState.bootstrap?.activeGameSessions || [];
    const selected = games.find((game) => String(game.id) === storedGame);
    if (selected) return launchGame(selected.id);
    renderGameSelection();
  }

  function initUi() {
    if (authState.initialized) return;
    authState.initialized = true;
    document.querySelectorAll("[data-auth-mode]").forEach((button) => button.addEventListener("click", () => setAuthMode(button.dataset.authMode)));
    document.getElementById("adminSignInForm")?.addEventListener("submit", handleSignIn);
    document.getElementById("adminForgotAccessCode")?.addEventListener("click", requestPasswordReset);
    document.getElementById("adminCreateForm")?.addEventListener("submit", handleCreate);
    document.getElementById("adminGameBack")?.addEventListener("click", showSignIn);
    void restoreSession();
  }

  window.EconovariaAdminAuth = {
    attachTerminal(terminal) {
      authState.terminal = terminal;
      if (document.readyState === "loading") document.addEventListener("DOMContentLoaded", initUi, { once: true });
      else initUi();
    },
    showSignIn
  };
})();
